startingCSS:
@keyframes spin {
  to { transform: rotate(360deg); }
}

.scene {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 1.5rem;
  padding: 2rem;
  background: #1e293b;
  border-radius: 10px;
}

.spinner {
  width: 48px;
  height: 48px;
  border: 4px solid #334155;
  border-top-color: #a855f7;
  border-radius: 50%;
  animation: spin 0.8s linear infinite;
}

.note {
  color: #94a3b8;
  font-size: 0.8rem;
  text-align: center;
  margin: 0;
  line-height: 1.6;
}

.note small {
  color: #475569;
  font-size: 0.72rem;
}

